def verify(answer):
    from sympy import symbols, simplify
    x = symbols('x')
    # sample even functions f(x)
    even_fs = [1, x**2, x**4]
    # sample odd functions g(x)
    odd_gs = [x, x**3, x**5]

    def is_zero(expr):
        return simplify(expr) == 0

    all_even = True
    all_odd = True
    for f in even_fs:
        for g in odd_gs:
            # h(x) = f(g(x**3))
            h = f.subs(x, g.subs(x, x**3))
            h_neg = h.subs(x, -x)
            if not is_zero(h_neg - h):
                all_even = False
            if not is_zero(h_neg + h):
                all_odd = False

    if all_even:
        correct = "even"
    elif all_odd:
        correct = "odd"
    else:
        correct = "neither"

    try:
        return str(answer).strip().lower() == correct
    except Exception:
        return False

