def verify(answer):
    import math
    # parse answer string
    try:
        ans = str(answer).strip().lower()
    except Exception:
        return False

    # numeric definition of the function, using real cube root
    def f(x):
        # real cube root preserving sign
        cbrt = math.copysign(abs(x) ** (1/3), x)
        return x / (x**2 + 1) + 3 * cbrt - 2 * x

    # test points (including negatives, zero)
    test_vals = [-10, -5, -2, -1, -0.5, -0.1, 0, 0.1, 0.5, 1, 2, 5, 10]
    tol = 1e-9

    even = True
    odd = True
    for x in test_vals:
        fx = f(x)
        fneg = f(-x)
        if abs(fneg - fx) > tol:
            even = False
        if abs(fneg + fx) > tol:
            odd = False

    if even and not odd:
        correct = "even"
    elif odd and not even:
        correct = "odd"
    else:
        correct = "neither"

    return ans == correct

