def verify(answer):
    from sympy import Rational, simplify, sympify
    # generate a few valid (a,b) pairs and compute the expression
    vals = set()
    for b_int in [2, -3, 5, 7]:          # b ≠ 0,1 ensures a is defined and non‑zero
