def verify(answer):
    from sympy import symbols, Poly, roots, nsimplify, Integer
    from collections import Counter

    # compute the exact roots (with multiplicities) of the polynomial
    x = symbols('x')
    poly = Poly(x**4 + 2*x**3 - 7*x**2 - 8*x + 12, x)
    root_dict = roots(poly)                     # {root: multiplicity}
    expected = []
    for r, m in root_dict.items():
        expected.extend([r] * m)

    # parse the candidate answer into a list of sympy numbers
    try:
        s = str(answer).strip()
        # allow optional surrounding brackets
        if s.startswith('[') and s.endswith(']'):
            s = s[1:-1]
        tokens = [t.strip() for t in s.split(',') if t.strip() != '']
        parsed = [nsimplify(tok) for tok in tokens]
    except Exception:
        return False

    # compare multisets (order does not matter, multiplicities must match)
    return Counter(expected) == Counter(parsed)

