def verify(answer):
    # generate primes up to 100
    def is_prime(n):
        if n < 2:
            return False
        if n % 2 == 0:
            return n == 2
        i = 3
        while i * i <= n:
            if n % i == 0:
                return False
            i += 2
        return True

    products = []
    for p1 in [2, 3, 5, 7]:          # 1‑digit primes
        p2 = 100 - p1
        if 10 <= p2 <= 99 and is_prime(p2):
            products.append(p1 * p2)

    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    if not products:
        return False
    # if there is a unique product, require exact match; otherwise accept any valid product
    return ans == products[0] if len(products) == 1 else ans in products

