from sympy import Matrix, Rational, sympify, simplify

def verify(answer):
    # Expected projection vector
    expected = Matrix([Rational(2, 5), Rational(-1, 5), Rational(0, 1)])

    # Helper to turn various answer forms into a 3‑element Matrix
    def to_matrix(ans):
        try:
            # Already a SymPy Matrix
            if isinstance(ans, Matrix):
                return ans
            # List or tuple
            if isinstance(ans, (list, tuple)):
                return Matrix(ans)
            # String representation
            s = str(ans).strip()
            # Try sympify directly (covers Matrix literals, lists, tuples)
            obj = sympify(s, evaluate=False)
            if isinstance(obj, Matrix):
                return obj
            if isinstance(obj, (list, tuple)):
                return Matrix(obj)
            # Fallback: parse comma/space separated numbers
            s = s.strip('[]()')
            parts = [sympify(p) for p in s.replace(',', ' ').split()]
            if len(parts) == 3:
                return Matrix(parts)
        except Exception:
            pass
        return None

    cand = to_matrix(answer)
    if cand is None or cand.shape != (3, 1):
        return False

    # Compare each component using exact equality
    for i in range(3):
        if simplify(cand[i] - expected[i]) != 0:
            return False
    return True

