def verify(answer):
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    # Given triangle DAO with AD = AO = 10 and DO = 12.
    # Height from A (or O) to base DO is the length OP we need.
    side = 10
    base = 12
    half_base = base // 2          # 6
    h2 = side * side - half_base * half_base  # squared height

    if h2 < 0:
        return False

    # Check if h2 is a perfect square
    h_int = int(math.isqrt(h2))
    if h_int * h_int == h2:
        height = h_int
    else:
        height = math.sqrt(h2)

    return ans == height

