    import re, math
    # expected solution intervals: (-inf, -7) U (1, 2)
    expected = [(-math.inf, -7, False, False), (1, 2, False, False)]

    try:
        s = str(answer).strip()
    except Exception:
        return False

    # normalize infinity symbols
    s = s.replace('∞', 'inf').replace('∞', 'inf')
    # split on union symbols (U, ∪, or comma between intervals)
    parts = re.split(r'\s*[U\u222A]\s*', s)

    intervals = []
    for part in parts:
        part = part.strip()
        if not part:
            continue
        m = re.match(r'([\(\[])\s*([^,]+)\s*,\s*([^)\]]+)\s*([\)\]])', part)
        if not m:
            return False
        low_inc = m.group(1) == '['
        high_inc = m.group(4) == ']'
        low_str, high_str = m.group(2), m.group(3)

        def conv(val):
            v = val.strip()
            if v.lower() in ('-inf', '-infinity', '-∞'):
                return -math.inf
            if v.lower() in ('inf', 'infinity', '∞'):
                return math.inf
            try:
                return int(v) if '.' not in v else float(v)
            except:
                return None

        low = conv(low_str)
        high = conv(high_str)
        if low is None or high is None:
            return False
        intervals.append((low, high, low_inc, high_inc))

    # sort intervals by lower bound for comparison
    intervals.sort(key=lambda x: (x[0], not x[2]))
    expected.sort(key=lambda x: (x[0], not x[2]))

    if len(intervals) != len(expected):
        return False
    for a, b in zip(intervals, expected):
        if a != b:
            return False
    return True

