from itertools import combinations
def verify(answer):
    # grid coordinates: (x,y) with x,y in {0,1,2}
    pads = [(x, y) for x in range(3) for y in range(3)]
    start = (0, 0)          # bottom‑left
    home = (2, 2)           # top‑right
    others = [p for p in pads if p not in (start, home)]
    # count subsets of 4 pads to remove (from the 7 others) that disconnect start from home
    bad = 0
    for rem in combinations(others, 4):
        removed = set(rem)
        remaining = {p for p in pads if p not in removed}
        # BFS from start
        stack = [start]
        visited = set()
        while stack:
            cur = stack.pop()
            if cur in visited:
                continue
            visited.add(cur)
            x, y = cur
            for nx, ny in ((x+1,y),(x-1,y),(x,y+1),(x,y-1)):
                nb = (nx, ny)
                if nb in remaining and nb not in visited:
                    stack.append(nb)
        if home not in visited:
            bad += 1
    try:
        return int(str(answer).strip()) == bad
    except Exception:
        return False

from itertools import combinations

def verify(answer):
    # parse candidate answer
    try:
        target = int(str(answer).strip())
    except Exception:
        return False

    balls = list(range(1, 17))
    total = 0

    # The block containing ball 1 is taken as the first block to avoid over‑counting
    for b1 in combinations(balls, 4):
        if 1 not in b1:
            continue
        set1 = set(b1)
        rem1 = set(balls) - set1

        # second block must contain the smallest remaining ball
        min2 = min(rem1)
        for b2 in combinations(sorted(rem1), 4):
            if min2 not in b2:
                continue
            set2 = set(b2)
            rem2 = rem1 - set2

            # third block must contain the smallest remaining ball
            min3 = min(rem2)
            for b3 in combinations(sorted(rem2), 4):
                if min3 not in b3:
                    continue
                set3 = set(b3)
                set4 = rem2 - set3  # the last block, automatically size 4

                blocks = [set1, set2, set3, set4]

                # verify the neighbour condition
                ok = True
                for i in range(1, 17):
                    # find the block containing i
                    for blk in blocks:
                        if i in blk:
                            if (i - 1) in blk or (i + 1) in blk:
                                break          # condition satisfied for this ball
                            else:
                                ok = False     # no neighbour in same block
                                break
                    if not ok:
                        break
                if ok:
                    total += 1

    return total == target

