from sympy import Rational, nsimplify

def verify(answer):
    # parse answer as a rational if possible, else as float
    s = str(answer).strip()
    try:
        r = Rational(s)
    except Exception:
        try:
            r = float(s)
        except Exception:
            return False

    # basic feasibility: |r| < 1 (required for convergence)
    try:
        if abs(float(r)) >= 1:
            return False
    except Exception:
        return False

    # check the defining cubic: 81*r**3 - 91*r + 10 == 0
    try:
        val = 81*r**3 - 91*r + 10
        if isinstance(r, Rational):
            if val != 0:
                return False
        else:
            if abs(val) > 1e-9:
                return False
    except Exception:
        return False

    # verify that the same first term yields the given sums
    try:
        a = 91*(1 - r)          # from original sum a/(1-r)=91
        if isinstance(r, Rational):
            ok1 = a/(1 - r) == 91
            ok2 = a/(1 - r**3) == 81
        else:
            ok1 = abs(a/(1 - r) - 91) < 1e-6
            ok2 = abs(a/(1 - r**3) - 81) < 1e-6
        return ok1 and ok2
    except Exception:
        return False

