def verify(answer):
    # Parse answer as a float
    try:
        R = float(str(answer).strip())
    except Exception:
        return False

    # Given side lengths
    sides = [5**0.5, 3, (20)**0.5, 5**0.5, 3, (20)**0.5]  # AB, BC, CD, DE, EF, FA

    # Radius must be at least half the longest side
    if R < max(sides) / 2 - 1e-9:
        return False

    # Compute sum of central angles corresponding to each side
    try:
        total_angle = sum(2 * asin(l / (2 * R)) for l in sides)
