from sympy import symbols, sqrt, Rational, integrate, simplify, N, sympify

def verify(answer):
    # parse answer defensively
    try:
        ans = sympify(str(answer))
    except Exception:
        try:
            ans = float(str(answer).strip())
        except Exception:
            return False

    # geometric computation
    t = symbols('t')
    sqrt3 = sqrt(3)
    A = (Rational(1, 2), sqrt3 / 2)   # vertex at 60°
    B = (-1, 0)                       # vertex at 180°
    x = (1 - t) * A[0] + t * B[0]
    y = (1 - t) * A[1] + t * B[1]
    d2 = simplify(x**2 + y**2)                # distance squared from center
    avg_d2 = integrate(d2, (t, 0, 1))          # average of distance squared
    expected = simplify((3 * sqrt3 / 2) * avg_d2)  # average area

    # compare numeric or symbolic
    if isinstance(ans, (int, float)):
        return abs(float(N(expected, 15)) - float(ans)) < 1e-9
    else:
        try:
            return simplify(ans - expected) == 0
        except Exception:
            return False

