from sympy import primerange
import math

def verify(answer):
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    # generate odd primes (small enough for our search)
    odd_primes = list(primerange(3, 200))  # 200 is ample for minimal case

    min_sum = None

    # case N = p^14
    for p in odd_primes:
        N = p**14
        # find factor pair with minimal sum
        limit = int(math.isqrt(N))
        for a in range(1, limit + 1, 2):
            if N % a == 0:
                b = N // a
                s = a + b
                if min_sum is None or s < min_sum:
                    min_sum = s

    # case N = p^4 * q^2  (p != q)
    for i, p in enumerate(odd_primes):
        for q in odd_primes[i+1:]:
            for exp_p, exp_q in [(4, 2), (2, 4)]:
                N = p**exp_p * q**exp_q
                limit = int(math.isqrt(N))
                for a in range(1, limit + 1, 2):
                    if N % a == 0:
                        b = N // a
                        s = a + b
                        if min_sum is None or s < min_sum:
                            min_sum = s

    return ans == (min_sum if min_sum is not None else -1)

