        if sa + sb < sb + sa:
            return 1    # b should come before a
        return 0

    order = sorted(range(1, 100000), key=cmp_to_key(cmp))
    try:
        idx = order.index(2025) + 1  # 1‑based index
    except ValueError:
        return False
    return target == idx

import re

def verify(answer):
    # enumerate all valid triples
    triples = []
    for a in range(1, 100):
        for b in range(a + 1, 100):
            for c in range(b + 1, 100):
                if a * b + c == 200:
                    triples.append((a, b, c))
    if not triples:
        return False

    # find minimal c-a
    min_diff = min(c - a for a, b, c in triples)
    best = [t for t in triples if t[2] - t[0] == min_diff]

    # problem states the triple is unique
    if len(best) != 1:
        return False
    a0, b0, c0 = best[0]

    # parse candidate answer for three integers
    try:
        nums = list(map(int, re.findall(r'-?\d+', str(answer))))
        if len(nums) != 3:
            return False
        a1, b1, c1 = nums
    except Exception:
        return False

    return (a1, b1, c1) == (a0, b0, c0)

def verify(answer):
    # Count ordered pairs (x, y) of positive integers with x+y <= 20
    # such that there exists a positive integer n with
    # n = lcm(n, x) - gcd(n, y).
    # This condition is equivalent to: x is even and (x/2) divides y.
    count = 0
    for x in range(1, 21):
