def verify(answer):
    import math, cmath
    # precompute roots of unity
    z = [cmath.exp(2j*math.pi*k/13) for k in range(13)]
    # effect of toggling lamp r (1..12)
    effects = []
    for r in range(1, 13):
        mask = 0
        mask |= 1 << r          # toggle itself
        left = (r - 1) % 13
        right = (r + 1) % 13
        if left != 0:
            mask |= 1 << left
        if right != 0:
            mask |= 1 << right
        effects.append(mask)
    max_mag = 0.0
    # enumerate all subsets of toggles (2^12 = 4096)
    for subset in range(1 << 12):
        state = 1  # lamp 0 is on (bit 0)
        for i in range(12):
            if (subset >> i) & 1:
                state ^= effects[i]
        # compute sum of positions of lamps that are on
        s = 0+0j
        for k in range(13):
            if (state >> k) & 1:
                s += z[k]
        mag = abs(s)
        if mag > max_mag:
            max_mag = mag
    try:
        cand = float(str(answer).strip())
        return abs(cand - max_mag) < 1e-9
    except Exception:
        return False

def verify(answer):
    from functools import lru_cache

    allowed = {"123", "231", "312"}

    @lru_cache(maxsize=None)
    def reducible(s: str) -> bool:
        if not s:
            return True
        n = len(s)
        for i in range(n - 2):
            if s[i:i + 3] in allowed:
                if reducible(s[:i] + s[i + 3:]):
                    return True
        return False

    count = 0

    def backtrack(pref: str, c1: int, c2: int, c3: int):
        nonlocal count
        if len(pref) == 15:
            if reducible(pref):
                count += 1
            return
        last = pref[-1] if pref else None
        if c1 and last != "1":
            backtrack(pref + "1", c1 - 1, c2, c3)
        if c2 and last != "2":
            backtrack(pref + "2", c1, c2 - 1, c3)
        if c3 and last != "3":
            backtrack(pref + "3", c1, c2, c3 - 1)

    backtrack("", 5, 5, 5)

    try:
        return int(str(answer).strip()) == count
    except Exception:
        return False

