    products = set()
    # possible cup counts are positive integers less than 32
    for a in range(1, 32):
        for b in range(a + 1, 32):
            for c in range(b + 1, 32):
                for d in range(c + 1, 32):
                    for e in range(d + 1, 32):
                        for f in range(e + 1, 32):
                            total = a + b + c + d + e + f
                            if total != 32:
                                continue
                            # check champion condition: one value equals sum of the others
                            vals = (a, b, c, d, e, f)
                            for i, v in enumerate(vals):
                                if 2 * v == total:   # v == sum of others
                                    others = vals[:i] + vals[i+1:]
                                    prod = 1
                                    for x in others:
                                        prod *= x
                                    products.add(prod)
                                    break
    # there should be exactly one possible product
    return len(products) == 1 and ans == next(iter(products))

def verify(answer):
