    for i in range(2, int(limit**0.5) + 1):
        if is_prime[i]:
            for j in range(i*i, limit+1, i):
                is_prime[j] = False
    primes = [i for i, p in enumerate(is_prime) if p]

    possible = set()
    # enumerate triples of primes (allow repetitions)
    for p in primes:
        for q in primes:
            for r in primes:
                # signs: each root is ±prime
                for s1 in (1, -1):
                    for s2 in (1, -1):
                        for s3 in (1, -1):
