    def vp_factorial(n, p):
        cnt = 0
        power = p
        while power <= n:
            cnt += n // power
            power *= p
        return cnt

    total = 0
    for n in range(11, 16):
        for p in (11, 13):
            total += vp_factorial(n, p)

    return ans == total

from itertools import product

def verify(answer):
    # board dimensions
    R, C = 4, 6
    N = R * C  # total cells = 24

    # all possible L‑triomino placements (as tuples of cell indices)
    placements = []
    for r in range(R - 1):
        for c in range(C - 1):
            base = [r * C + c, r * C + (c + 1), (r + 1) * C + c, (r + 1) * C + (c + 1)]
            for miss in range(4):
                shape = tuple(base[i] for i in range(4) if i != miss)
                placements.append(shape)

    # pre‑compute orthogonal neighbours for each cell
    neigh = [[] for _ in range(N)]
    for i in range(N):
        r, c = divmod(i, C)
        for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C:
                neigh[i].append(nr * C + nc)

    total_colorings = 0

    # backtracking over tilings
    used = [False] * N
    tiling = []  # list of placements (each a tuple of 3 indices)

    def dfs():
        nonlocal total_colorings
        # find first empty cell
        try:
            first = used.index(False)
        except ValueError:
            # full tiling obtained
            # build adjacency matrix
            m = len(tiling)  # should be 8
            adj = [[False]*m for _ in range(m)]
            cell_sets = [set(p) for p in tiling]
            for i in range(m):
                for j in range(i+1, m):
                    # check if any cell of i touches any cell of j
                    if any(nb in cell_sets[j] for cell in cell_sets[i] for nb in neigh[cell]):
                        adj[i][j] = adj[j][i] = True
            # count proper 3‑colorings
            count = 0
            for colors in product(range(3), repeat=m):
                ok = True
                for i in range(m):
                    ci = colors[i]
                    for j in range(i+1, m):
                        if adj[i][j] and ci == colors[j]:
                            ok = False
                            break
                    if not ok:
                        break
                if ok:
                    count += 1
            total_colorings += count
            return

        # try all placements covering 'first' that are still free
        for shape in placements:
            if first not in shape:
                continue
            if any(used[cell] for cell in shape):
                continue
            # place it
            for cell in shape:
                used[cell] = True
            tiling.append(shape)
            dfs()
            tiling.pop()
            for cell in shape:
                used[cell] = False

    dfs()

    try:
        return int(str(answer).strip()) == total_colorings
    except Exception:
        return False

from itertools import combinations
from collections import deque

def _can_reduce(s: str) -> bool:
    patterns = {"123", "231", "312"}
    seen = {s}
    q = deque([s])
    while q:
        cur = q.popleft()
        if not cur:
            return True
        n = len(cur)
        for i in range(n - 2):
            sub = cur[i:i+3]
            if sub in patterns:
                nxt = cur[:i] + cur[i+3:]
                if nxt not in seen:
                    seen.add(nxt)
                    q.append(nxt)
    return False

def verify(answer) -> bool:
    try:
        target = int(str(answer).strip())
    except Exception:
        return False

    total = 0
    n = 15
    positions = range(n)

    # choose positions for the five '1's
    for ones in combinations(positions, 5):
        ones_set = set(ones)
        remaining_after_ones = [p for p in positions if p not in ones_set]

        # choose positions for the five '2's among the remaining
        for twos in combinations(remaining_after_ones, 5):
            twos_set = set(twos)

            # build the string: default '3's, then place '1's and '2's
            chars = ['3'] * n
            for i in ones_set:
                chars[i] = '1'
            for i in twos_set:
                chars[i] = '2'
            s = ''.join(chars)

            # condition 1: no equal adjacent characters
            if any(s[i] == s[i+1] for i in range(n-1)):
                continue

            # condition 2: reducible by deleting 123, 231, 312 substrings
            if _can_reduce(s):
                total += 1

    return total == target
